#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5,INF=(1LL<<31)-1;
map<int,int> last;
int n,a[N],b[N],l[N],r[N],ans[N],p[N];
bool cmp(int x,int y){
    return a[x]<a[y];
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        b[i]=i;
        if(!last[a[i]])
            last[a[i]]=i;
    }
    sort(b+1,b+n+1,cmp);
    stack<int> s;
    for(int i=1;i<=n;i++){
        while(s.size() && b[s.top()]>b[i])
            r[s.top()]=i,s.pop();
        s.push(i);
    }
    while(s.size())
        s.pop();
    for(int i=n;i;i--){
        while(s.size() && b[s.top()]>b[i])
            l[s.top()]=i,s.pop();
        s.push(i);
    }
    for(int i=1;i<=n;i++){
        int x=b[i];
        if(x==1)
            continue;
        ans[x]=min((l[i]?a[x]-a[b[l[i]]]:INF),(r[i]?a[b[r[i]]]-a[x]:INF));
        if((l[i]?a[x]-a[b[l[i]]]:INF)<(r[i]?a[b[r[i]]]-a[x]:INF))
            p[x]=last[a[b[l[i]]]];
        else if((l[i]?a[x]-a[b[l[i]]]:INF)>(r[i]?a[b[r[i]]]-a[x]:INF))
            p[x]=last[a[b[r[i]]]];
        else
            p[x]=last[a[b[l[i]]]];
    }
    for(int i=2;i<=n;i++)
        printf("%d %d\n",ans[i],p[i]);
    return 0;
}
